INSERT INTO `courses` (`id`, `course_code`, `course_name`, `department`, `professor`, `class_group`, `classroom`, `confirmed_students`, `cono`, `credits`, `grade`, `helf`, `max_students`, `open_year`, `pclass`, `remarks`, `required_elective`, `sclass`, `time_thu`, `updated_at`, `average_rating`, `class_day`, `class_period`, `sdgs`, `course_objectives`) VALUES
(1, 'A012', '生活經濟學', 'SO', '鄭義暉', 'A', 'M01-206', 60, NULL, 2, 1, '2', 60, '114', 'A', '管院同學請勿選修', '選', NULL, NULL, NULL, 0, '四', '3,4', '10', '人類的經濟生活及社會網絡活動，不論以有形的或無形的方式，以無所不在的巨大力量推動著這動態複雜的社會往前進。本課程的教學目標在於提供學生經濟學原理的理論基礎，將聚焦在圍繞著我們每天生活的12種具有重要影響力的主題，透過經濟學知識的介紹，將實際觀察的生活案例加以歸納分析，並且提出未來遇到相似情境時的應變之道。透過本課程的引導，期望學生能夠應用以不同的視野來看待生活周遭的經濟生活樣貌，將所學基本觀念與知識，具有認識、分析與解決經濟問題的能力，並進而建立自行思考政府政策對本身及其經濟社會之影響，同時對於建構未來的美好生活及幸福社會，有更多的反思與革新願景。'),
(2, 'A034', '個人理財與投資', 'SO', '黃旭輝', 'A', 'M01-103', 60, NULL, 2, 1, '2', 60, '114', 'A', '管院請勿選修', '選', NULL, NULL, NULL, 0, '三', '7,8', '01,08,02', '本課程的主要目的在於讓學生對於投資環境,金融市場以及金融商品有一初步的認識，同時也透過課外讀物的閱讀讓學生能將理論與實務的投資結合，以使學生有完整並實用的理財觀念。透過這門課老師在課堂上的講解以及課外投資讀本可讓學生培養其財務金融相關的科學素養，而理論與實務的的結合則有助於提升學生的思維方法，課堂上的互動討論則可進一步啟發學生的創新思維。'),
(3, 'A062', '統計與生活', 'SO', '郭錕霖', 'A', 'C02-108', 60, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '一', '7,8', '', '透過生活經驗，加入統計思維，冀望創建更優質的生活模式。'),
(4, 'A183', '性別與法律', 'SO', '陳玫君', 'A', 'B01-109', 53, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '二', '5,6', '05,10,16', '一、建立性別平等應有之認識。 二、介紹性別相關國際規範，包含《消除對婦女一切形式歧視公約內容》，並透過性別案例與判決介紹CEDAW公約內容及如何落實性別主流化內容。 三、介紹與性、性別相關之法規範，讓學生了解在校園、職場及各種場域可能發生之性別議題與法律規範，以及情侶交往、 夫妻關係常見之性別法律問題，透過社會事件解析，提升性別平等之意識外，學習相關法律規範，並培養學生相關之法律素養與解決問題之能力。 四、透過相關性別法律規範學習及案例分析，增進危險預防、面對問題及解決問題之能力。'),
(5, 'A188', '多元性別與親密關係', 'SO', '陳靜儀', 'A', 'B01-108', 51, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '四', '5,6', '05,10,16', '性別平等教育必須建基於對多元文化社會所產生的覺知、信念和行動。其目的在於教導學生認知個人的成長發展，與社會文化脈絡有著密不可分的依存關係。個人需透過與不同性別者的互動，進行性別角色的學習與突破，從而接納自我性別特質與性別認同，以培養自尊自信的生活態度。 本課程係從性別議題切入自我概念的建構與生涯發展，破除性別刻板印象及社會桎梏，找回自我認同。繼而學習經營健康的親密關係，擁有尊重與和諧的關係。'),
(6, 'A189', '性別與法律', 'SO', '張峰維', 'A', 'M01-206', 21, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '二', '5,6', '05,10,16', '本課程以男性女性的社會法律生活中以及男女平等的實現上，進行專題內容的思考。考慮本課程為通識課程，在法律專業領域部分盡可能以簡短容易瞭解方向進行。具體內容以男性女性常會面臨的法律問題為探討範圍，不依照傳統法律學習從民法、刑法、行政法…等個別法律屬性，特別注重於男性女性生涯中會歷經的幾個重要階段的問題為主。希望透過本課程的學習，對男性女性的生涯的法律糾紛的預防與解決，有所助益，也能在當中習得法律的基礎知識。一般法律課程多著重於理論的傳輸，然本課程盡可能採用視聽多媒體輔助教材，並佐以實例來配合說明，沖淡法律課程艱澀難懂的氣氛。課程名稱定名為「性別與法律」，著眼於異性別共處的社會生活中，男性女性更應瞭解彼此的需求與人生各階段會面臨的問題，不同性別之間才因互相瞭解而彼此包容，以邁向和樂家庭與和諧社會。本課程探討議題如下： （1）性與性別：性騷擾與性侵害、優生保健與生育自主、性工作權。 （2）婚姻與家庭：國際婚姻與家務移工、家庭暴力、夫妻財產的性別平等。 （3）職場與社會：職場勞動與性別平等、婦女保障與參政權、生育與性別平等。'),
(7, 'A226', '國際會展公關禮儀', 'SO', '張秀瓊', 'A', 'B01-107', 59, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '三', '5,6', '17,04,08', '國際會展產業是國家龍頭產業，然而南臺灣對此產業陌生，導致人才極度缺乏。 高雄國際化腳步緊接台北之後，國際會議及展覽舉辦與時日增，加強國際會展公關禮儀為企業界當務之急。 國際會展MICE接待禮儀在於培訓職場受歡迎的人才，幫助學生成為更好的自己。 114-2學期會加強AI融入課程讓學生發揮創意孰悉國際會展專業人才'),
(8, 'A353', '婚姻與家庭', 'SO', '陳靜儀', 'A', 'B01-108', 52, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '四', '3,4', '05,16,03', '隨著社會變遷，家庭組織與功能也隨之變化。即使家庭結構、兩性家庭角色、生育行為、婚姻與親子關係等面臨與過往有極大的不同及挑戰，婚姻與家庭制度仍是滿足人類基本需求不可或缺的社會機制。 本課程係從何謂「愛」與「許諾」闡釋進入婚姻與家庭的理由，了解婚姻與家庭的動態發展、如何適應和經營、以及覺察原生家庭系統帶來的影響，繼而學習營造健康的家庭與高品質的婚姻生活、擁有尊重與和諧的關係的能力。'),
(9, 'A365', '領導統御', 'SO', '蔣遠平', 'A', 'B01-103', 59, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '五', '3,4', '01,11,13', '本課程係本校通識教育課程規劃中，教學目標： 一.培養學生人文反思，符合學校「基本素養」指標之「人文素養」與「倫理素養」，藉軍事及商業運用成功實例可成就學生的能力為「知識力」及「品格力」使其知道如何運用現有的資源開創有利的條件及機勢，進而掌握人生勝利的契機。 二.本課程希望能達成以下幾點具體目標，養成學生相關的能力： １.探索自我發展潛能：能透過對《領導統御》的探索，對自身的經驗或存在境遇，進行觀照與反思。 ２.培養獨立思考與解決問題的能力： （１）能對論題與論點進行必要的檢證與考察。 （２）能在對議題進行研究之後，提出自己的見解。 ３.鑑賞、表現與創新： 能對文本進行閱讀、理解，與全心詮釋；並能有條理與脈絡的進行鑑賞與評論。'),
(10, 'A366', '國際關係', 'SO', '楊筑尹', 'A', 'L02-108', 60, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '一', '7,8', '16,17,10', '國際觀的建立及培養，除了國際新聞閱讀及出國交流外，更需要透過對國際關係概念認識與理解，使學生對國際議題的理解具有穿透性，能具有獨立思考及批判的能力。隨著全球化浪潮發展，國家之間或人與人之間的互動日趨頻繁，國際體系的行為者包括國家、個人、跨國組織等趨於多元化，而國際議題除了國家安全或軍事外交的傳統安全主題外，全球發展不均、恐怖主義、能源與氣候變遷等非傳統安全議題不僅引起各國政府關注，亦與生活在此地球村的每個人息息相關。本課程透過單元主題設計，呈現國際關係理論、基本概念之介紹，並藉由解析國際議題的發展及現況，引導同學運用國際關係概念理解及分析國際政治現象，兼顧認識國際關係概念之深度與理解國際現勢發展之廣度。 1.培養學生的國際觀及宏觀之視野。 2.建立學生對國際關係基本概念、理論及重要國際議題之理解力。 3.藉由系統性的介紹及分析國際關係理論，以期能增進學生對國際政治現象及重要議題的敏感度與分析能力。'),
(11, 'A367', '孫子兵法', 'SO', '蔣遠平', 'A', 'B01-103', 53, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '五', '1,2', '09,01,17', '本課程係本校通識教育課程規劃中，教學目標： 一.培養學生人文反思，符合學校「基本素養」指標之「人文素養」與「倫理素養」，藉軍事及商業運用成功實例可成就學生的能力為「知識力」及「品格力」使其知道如何運用現有的資源開創有利的條件及機勢，進而掌握人生勝利的契機。 二.本課程希望能達成以下幾點具體目標，養成學生相關的能力： １.探索自我發展潛能：能透過對《孫子兵法》的探索，對自身的經驗或存在境遇，進行觀照與反思。 ２.培養獨立思考與解決問題的能力： （１）能對論題與論點進行必要的檢證與考察。 （２）能在對議題進行研究之後，提出自己的見解。 ３.鑑賞、表現與創新： 能對文本進行閱讀、理解，與全心詮釋；並能有條理與脈絡的進行鑑賞與評論。'),
(12, 'A368', '國際文化探索', 'SO', '王靜嫻', 'A', 'B01-103', 40, NULL, 2, 1, '2', 40, '114', 'A', '', '選', NULL, NULL, NULL, 0, '三', '5,6', '17,03,04', 'Thiscoursefallsunderthedomainofglobalandinterculturalstudies, offeredasageneraleducationelective. Drawinguponperspectivesfromculturalstudies, sociologyandinternationalrelations, thecourseintroducesstudentstothediversityofculturesaroundtheworld. Emphasisisplacedonunderstandingculturalvalues, socialbehaviors, andinterculturalissuesacrossvariousregions. Itisdesignedspecificallyforbothinternationalstudentsandlocalstudentsandencouragesthemtoengagewithglobalculturesthroughcasestudies, media, groupdiscussions, andexperientiallearningactivities.'),
(13, 'A619', '台灣與全球化', 'SO', '洪聖斐', 'A', 'B01-109', 60, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '五', '5,6', '16,17,10', 'ThiscourseaimstoprovidestudentsapictureofTaiwaninthecontextofglobalization. Throughoutthehistory, Taiwanhasalwaysbeenimpactedbyglobalization. Infact, theverynames “Taiwan” and “Formosa” themselvesaretheproductsofglobalization. OnemayhaveatotallydifferentunderstandingofTaiwanintheperspectiveofglobalization. ThiscoursetracesthehistoryofTaiwansincethepaleolithicagetothe21stcenturyandofferexplanationsfromtheviewofglobalization. Thiscoursewillprovideanopportunityforstudentstoexploretheinteractionsandthepoliticalandeconomiccalculationsoftheactors. Thiscourseofferslocalstudentsanewviewoftheirhomelandandintroduceinternationalstudentsahistorictourofthisbeautifulisland. Fieldtripstohistoricscenesareincluded.'),
(14, 'A620', '台灣壯遊', 'SO', '翁烔慶 洪聖斐', 'A', 'B01-109', 20, NULL, 2, 1, '2', 20, '114', 'A', '', '選', NULL, NULL, NULL, 0, '五', '3,4', '11,17,15', '本課程是國立高雄大學〈台灣學〉課群的第一門課，也是本校與遍部台灣各地（包含臺北市立大學、國立宜蘭大學、國立暨南國際大學、國立嘉義大學、臺南藝術大學、國立屏東大學、國立台東大學、國立澎湖科技大學、國立金門大學）的聯盟學校合作開設的課程。目的是為了幫助同學藉由實際走讀，瞭解台灣各地風土民情與歷史地理，培養與土地的感情與人文關懷。 修課同學除了期初在本校聽教師授課外，亦將收看由各聯盟學校所提供的影音教材，並從中選擇想要去走讀的路線（各校老師會帶領你們前去走讀）。產生的交通費、住宿費由同學自行負擔，學校部分補助。'),
(15, 'A691', '高大卓越講座', 'SO', '陳志文 吳行浩', 'A', 'L01-201', 200, NULL, 2, 1, '2', 200, '114', 'A', '1.修過「高大卓越講座(一).(二)」者請勿重覆選修,重覆選修不列入學分計算。2.若有課程相關問題請連繫<推廣教育中心>', '選', NULL, NULL, NULL, 0, '二', '6,7', '04', '高大卓越講座致力於邀請各領域表現卓越的先進蒞校演講，讓學生在固定課程修習外，有機會接觸到多元知識範疇，期望透過各界卓越人士向學生傳遞成就經驗中的重要精華，讓學生親炙大師、效法典範，引導學子朝向正面人生，開拓通達視野。'),
(16, 'A840', '媒體與公關實務', 'SO', '鄭為松', 'A', 'B01-103', 28, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '三', '10,11', '04,10,16', '你今天滑Threads、IG（Instagram）、Dcard，還是傳訊息給朋友Line了嗎？ 在日常生活中，我們透過社群媒體分享、打卡、按讚、訂閱與轉發，早已成為習慣。然而，媒體的影響早已不限於個人領域，從企業品牌行銷到政府政策宣傳，現今社會愈來愈倚重媒體操作來推動公共關係、建立形象與傳遞價值。 在這樣的媒體環境中，具備靈活運用媒體的能力，能正確解讀訊息、有效傳達觀點，乃至避免踩雷與誤判，已是現代公民不可或缺的素養。 本課程以「媒體」與「公共關係」兩大核心為主軸： 媒體面向引導學生認識當代媒體生態，並從中培養「文字」與「影像」兩種敘事力；公共關係面向則介紹公關產業的運作邏輯與實務技巧，輔以真實案例剖析，幫助學生理解如何與媒體互動、建立良好形象與策略傳播。 課程鼓勵學生正向理解與善用媒體特性，透過觀察、表達與實作訓練，提升個人敘事能力與傳播素養。 本課程不設期中與期末筆試，重視實務操作，評量將以「期中報告」、「期末報告」、「課堂參與」、「反思回饋」、「彈性修業（心得）」等5向度各20%進行綜合考核。'),
(17, 'A863', '行政學的世界', 'SO', '楊戊龍', 'A', 'L02-108', 49, NULL, 2, 1, '2', 60, '114', 'A', '政法系請勿選修', '選', NULL, NULL, NULL, 0, '三', '7,8', '16,05', '1.認識行政管理的主要議題； 2.認識官僚組織理論； 3.認識瞭解政府機關的運作與管理； 4.討論政府改造的成敗。'),
(18, 'A887', '關懷倫理與永續發展', 'SO', '陳靜儀', 'A', 'M01-102', 38, NULL, 2, 1, '2', 40, '114', 'A', '', '選', NULL, NULL, NULL, 0, '五', '3,4', '12,11,16', '本課程以關懷倫理為核心，探討永續發展的不同面向，涵蓋理論探討，也強調實踐應用，希望能引導學生將關懷倫理內化為自身的行動準則。 課程目標一、瞭解關懷倫理的基本理論與其在永續發展議題中的應用。 二、探討環境永續、社會責任與經濟發展的倫理挑戰。 三、培養學生批判性思維與行動導向，促進永續發展實踐。'),
(19, 'A892', '金融陷阱', 'SO', '蔡宗廷', 'A', 'B01-104', 60, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '一', '5,6', '01,04,08', '許多人覺得，金融體系彷彿是在另一個世界運作，和一般人過生活的世界不同，事實上，我們幾乎每天都與它打交道，可能是存錢、開支票、到自動提款機前提領現金、消費使用信用卡，甚至是貸款、投資股票或基金，金融體系跟你我的生活早就緊密結合。 經濟活動，其實就是人跟市場的互動糾葛，愛恨情仇，興衰勝敗，不管你懂不懂這些經濟學或金融的專有名詞，沒有人能置身其外。從大家熟知的股票、債券到複雜的衍生性金融商品，本書將會說明金融市場架上的每一種產品在幹什麼、如何創造以及怎麼操作，到大規模的總體經濟政策及當前的金融危機都有完整介紹。讓你更了解市場如何運作、誰會去買哪些東西以及背後的理由。你很快就能分辨哪些產品很安全，哪些產品有風險，也會懂得如何去分辨市場的缺失。 作者PaddyHirsch本身是資深華爾街財經記者，在國家廣播頻道（NPR）主持超過9百萬人次，擁有超高收聽率的財經節目「Marketplace」，以幽默的文筆、淺白生動的比喻，並加上美國知名插畫家DanArcher的漫畫，讓閱讀的過程充滿驚喜。'),
(20, 'A956', '權力遊戲與國際社會', 'SO', '李鐵生', 'A', 'B01-109', 60, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '一', '5,6', '17', '本課程是一門有趣的國際社會課程，概述「權力轉移理論」(PowerTransition)、「賽局理論」(GameTheory)及「易經卦象戰略」在國際關係中之應用。前者為「權力」，後兩項為「遊戲」策略，則為此科目名「權力遊戲」之由來。修過本人「探索台灣–政經篇」的同學可以不必再修，因為本課程仍然是從「權力轉移」(PowerTransition)為核心出發，另外除了權力(權力轉移理論)將向學生介紹許多遊戲(賽局，卦象，game)概念，這是因應「權力轉移」核心理論，發展的因應策略，包括西方與東方的戰略。西方以賽局理論(GameTheory)為出發點；東方則以易經(孫子兵法的源頭)為出發點。會介紹納許均衡、最佳策略、以及易經卦象策略。 這些概念將被用來研究國際關係中的問題，如超級大國競爭、國際合作、國際討價還價、兩岸貿易關係等。雖然我們將探索的許多應用程序都集中在政治或全球現象，而應用程序卻來自經濟和個人日常生活領域，這正是賽局理論最迷人的地方。本課程教育學生如何分析、判斷與預測個體(大至國家)互動，除有助於建立學生之相關『公民素養』，並提升其對常見各種互動樣態之基本認識並建立系統化的解釋方式與思考邏輯；同時，藉由對群體互動之更深層認識，加強學生之『國際社會關懷』素養。'),
(21, 'A972', '壓力情緒管理', 'SO', '柯慈姍', 'A', 'B01-109', 60, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '二', '10,11', '03', '情緒壓力是現代人最常面臨的問題之一，尤其是大學生，在這個成長的風暴期中，面對壓力時，常常不知如何紓發與自處，多數人僅能默默承受，期待著事件能儘快落幕，一切回復正常，殊不知在如此消極的方式下，陷於長期的壓力情緒，導致更嚴重的心理問題。 本課程旨在透過課程講授、團體分組討論與主題活動等方式的進行，每週針對不同主題的情緒壓力議題進行討論與分享，讓學生在輕鬆有趣的氣氛中認識與自身相關的壓力來源、影響，並藉由同儕討論與分享、分析過程，凝聚共識、增進普同感，學習如何找到情緒出口、與壓力共存、管理自己與他人的情緒。 1.透過課程講授以及團體活動的方式讓學生了解壓力的來源與影響。 2.透過同儕互動與討論，找到情緒出口、紓解壓力。 3.透過情緒日誌的記錄，讓同學能覺察情緒變化與尋找因應方式。'),
(22, 'B012', '民營化的迷思', 'SO', '蔡宗廷', 'A', 'B01-104', 59, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '一', '7,8', '10,16,17', '尚未移轉民營，卻正在研議、進行中的公營事業，由於無法檢証，所以將討論的焦點限縮於事業民營化的過程中公共性或普及服務應如何保障的部分，以作為是否推行民營化政策的論證輔佐。'),
(23, 'B051', '智慧財產權', 'SO', '陳玫君', 'A', 'B01-109', 39, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '二', '3,4', '08,16,09', '一、透過智慧財產權法制相關原理原則與實務問題之解析與介紹，建立著作權法、專利法、商標法及營業秘密法等初步之認識，並介紹相關之概念、要件、權利歸屬、類型、內容、效力及實例，培養學生在生活中運用及解決相關智慧財產議題之能力。 二、智慧財產權之專業從事人才，除法律相關科系可從事，更亟需其他跨領域如理、工、醫、農、生命科學、生物科技、資訊、管理、商學等領域之人才，讓各系所領域同學透過修習本課程，建立跨域及多元就業管道之智慧財產權之專業知識。 三、智慧財產權法對於個人創作者及企業都非常重要，除避免侵犯他人創作、保護個人創作不被侵犯，同時也能激勵創新與發明；對企業而言，智慧財產權保護機制，更是保持競爭力之關鍵。 四、人工智慧在全球智慧財產權領域日益重要，透過學習本課程智慧財產權相關知識，去解決並思考新型人工智慧所產生的各種問題。'),
(24, 'B055', 'AI時代法學議題', 'SO', '康銘', 'A', 'L02-107', 60, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '三', '5,6', '04,09,10', '約從1950年代起，科技即開始朝向對如何發展出(類人)機器的探索研究與發展而努力，拜巨量資料與所謂「機器學習」之賜，使該研究有了飛躍的突破與進展，並從人工智慧(ArtificialIntelligence, AI)的探究發展，進而影響長久以來人類社會觀念的轉變，並延伸出未來是否有取代人類可能性的議題討論。 時至今日，AI人工智慧的運用越來越廣泛，遍及各個生活領域且虛實交錯，特別是在全球化的大環境下，AI將會使不同的文化與價值觀進行與異於過去傳統思維的碰撞，進而形塑出新的價值觀。面對瞬息萬變的AI科技發展，無論是哪一種法領域，均已然形成各式新的挑戰，如何發展建立新的法學系譜與思維途徑，當屬理所當然且刻不容緩的問題。 本課程規劃兩大討論範疇，首先針對AI人工智慧時代對法學影響大哉問，討論內容包括AI科技發展對傳統社會倫理道德的衝擊及影響、對現行法律保護重要法益等議題作探討。次而就目前AI發展應用於社會各種領域所衍生的法律問題，分別從現行法律保護要件思維與AI發展應用實況，作比較與衝突調和方面討論。最後並就歐盟《人工智慧法》（ArtificialIntelligenceAct，AIA）與我國《人工智慧基本法草案》規範簡略介紹，希冀同學就AI時代面臨(產生)法律各種衝突問題時，能具備基本的認識與新的思維能力。'),
(25, 'B091', '國際禮儀', 'SO', '陳永安', 'A', 'B01-108', 60, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '一', '3,4', '05,10,03', '現代大學生的核心競爭力為八大素養，八大素養則為：人文素養、創意創新、國際視野、團隊合作、信心毅力、主動學習、專業倫理及領導管理。「國際禮儀」課程目標為培養「八大素養」中之「國際視野」、「人文素養」、「團隊合作」及「信心毅力」。 藉由國際禮儀教學，提升學生「衣、食、住、行、育、樂」的禮儀，強化未來就業優勢，培養學生國際視野之素養。'),
(26, 'B101', '服務學習', 'SO', '邱昭文', 'A', 'C02-107', 35, NULL, 3, 1, '2', 40, '114', 'A', '', '選', NULL, NULL, NULL, 0, '一', '8,9, 10', '04,05', '協助國教端(偏鄉國小為主)進行戶外科普活動、校內服務議題、科學教具製作。期間將於課堂上先透過分組討論模擬科普實驗教學下所需準備的前置作業與活動當天的注意事項，並訓練同學相關自然科學背景知識，隨後同學需進行相關科普活動或教具製作、從事校內相關服務議題或校外服務超過40小時，於課程結束前會做課程回顧及心得分享與交流。 然而, 若因COVID-19疫情影響而採行遠距線上授課時, 課程的登入代碼如下： https://meet.google.com/fxt-vryy-xid以達停課不停學之目的.'),
(27, 'B102', '服務學習', 'SO', '陳致仁', 'A', 'B01-105', 35, NULL, 3, 1, '2', 40, '114', 'A', '', '選', NULL, NULL, NULL, 0, '四', '8,9, 10', '01,03,16', '知識的傳授，並無法圓滿人格。大學教育的目的之一，是讓學生跟社會可以無縫接軌，而人格的養成也是項目之一。 “Duetothedemandsofheavycourseloadsandpart-timejobs, manystudentsdonotventurefarfromtheirlocalneighborhoodsortheuniversitydistrict. Participation…mayrequiretakinganewbusroutetotheinnercityoranunfamiliarneighborhood. Itrequireslearningaboutlocalorganizations, theirstructures, andtheirfunding, andmeetingandinterviewingstaffmembersanddirectors.” ~LucyJaroszandKimJohnson-BogartinNewConceptsoftheRelationshipBetweenCollegeandCommunity: ThePotentialofService-Learninghttps://libguides.nyit.edu/c.php?g=837082&p=5978581'),
(28, 'A035', '佛教的人生智慧', 'LI', '林于盛', 'A', 'B01-103', 57, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '二', '5,6', '10', '本課程遠距上課時，請直接進入https://meet.google.com/vwh-ayse-btg。若有變革，請自行密切注意Moodle4.0教學平台之本課程公告。 佛教乃世界重要宗教之一，影響中國文化至深至大，因此作為現代之高級知識分子，應該對其有所了解。是故本課程並非意在鼓吹信仰佛教以排斥其他宗教、哲學，而是旨在提供學生對佛教的基本認識，增益自身的人文素養，並汲取甚或質疑其生命觀點，以反省、改善現實的生活。課程內容由生命的可能困境與中國文化中的佛教成分談起，令學生較易有所感受；而逐步建立佛教發展史與核心教義的觀念；再分別介紹若干經籍篇章、修行宗派、生活議題，以增加具體印象。至於教材選擇，主要以「智慧與幽默」兩大方向為考量，即盡量選取具有生命智慧深度，且體現佛教特有之修辭、悟境的人生幽默，作為實際講授的對象。希望能在趣味之中，引發思維。 本課程係博雅中文通識課程，目的在促使學習者習得並發展本校之四大核心能力---- (一)在增加知識力方面：增益宗教相關聞見 (二)在開發創造力方面：擴大人文思維面向 (三)在厚實品格力方面：陶冶內在道德修養 (四)在強化社會力方面：落實社會關懷精神據此，希望能在本校通識課程基本能力項目的養成上，主要達致以下之具體目標： (一)「探索自我與發展潛能」：觸發「內省觀照自我的身心狀態、探究生命存在的實相與價值、坦然面對生死現象」之心智態度 (二)「獨立思考與解決問題」：針對佛教的基本教義進行初步反思與評論、選擇感興趣之佛教議題進行基本資料的檢索與考察 (三)「鑑賞、表現與創新」：能夠描述佛教的歷史發展概況、說明佛教對中國文化各方面的大概影響、觀摩並使用兼具智慧與幽默的語文表達技巧、引用佛教術語與典故於文藝方面等等之創作 (四)「尊重生態與倫理關懷」：培養「善待一切眾生處境、提升人己生命境界」之慈悲喜捨的內在心量與行為習慣'),
(29, 'A036', '禪宗經典智慧', 'LI', '蕭愛蓉', 'A', 'B01-107', 32, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '二', '5,6', '10,03,16', '本課程主要根據禪宗經典《六祖壇經》、《景德傳燈錄》及《正法眼藏》，探討禪的生命智慧、生活逸趣及社會應用。同時，本課程亦教授禪修方法，結合經典要義及實際操持，引導學生透過禪理探討及禪法演練以探索自我、安頓身心，並了解禪宗的般若智及菩提心。期望學生能透過本學期的課程，體會禪宗「悲智雙運」之精神，並以此深入省察自我，思考如何提升生活品質，把握禪宗對個體生命、群體生活的具體應用。'),
(30, 'A055', '台灣紀錄片的美學與政治', 'LI', '徐國明', 'A', 'B01-106', 60, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '五', '5,6', '10,16,05', '不同於劇情片的虛構特質和產製模式，紀錄片的創作形式不只是以真實的人、事、物為基礎，在攝製方式上也相對比較不受限制。一般來說，紀錄片作為一種影像策略基於不同的拍攝目的，大致可區分為藝術創作、美學實驗、歷史文獻、研究方法、政治行動或教育過程，展現多元紛呈的美學及政治光譜。因此，產製於台灣社會不同時期的紀錄片作品，多多少少也反映出當時的政治體制和文化脈動，宛如時代的鏡面。由此，本課程的教學目標有三：其一，從台灣紀錄片的生產脈絡，發掘背後多重力系的作用，藉此提點有關影像與再現之間複雜的視覺權力關係；其二，引介台灣紀錄片的發展歷程和重要作品，指定閱讀相關文獻，用以掌握知識範疇；其三，針對紀錄片作品撰寫影像評論，提升語文專業、批判思考和文化論述的能力。'),
(31, 'A114', '日本繪本', 'LI', '錢秋茜', 'A', 'B01-105', 36, NULL, 2, 1, '2', 60, '114', 'A', '本課程需具備50音基礎', '選', NULL, NULL, NULL, 0, '五', '5,6', '04,17,16', '繪本，日文用漢字為 \"絵本（）\"，英文稱PictureBook，意思就是「畫出來的書」，指內容以繪畫為主，並附有少量文字的書籍；繪本和普通的圖畫書有區別，繪本不僅是講故事，學知識，而且可以幫助幼童專注學習，培養多元智能，提高聆聽與學習興趣。 本課程藉由介紹日本繪本的歷史與型態，並透過精選之繪本，引導同學瞭解日本兒童文學與異國文化，透過小組討論與分享，發揮想像力與創作力。 **本課程須具備50音基礎**'),
(32, 'A170', '新詩創作', 'LI', '張忠進', 'A', 'B01-106', 60, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '五', '7,8', '04,05,11', '1、認識現代詩的發展與理論2、培養析賞現代詩的興趣3、提昇析賞現代詩的能力4、指導寫作現代詩5、提升人文素養變化氣質'),
(33, 'A184', '現代文學選讀與習作', 'LI', '張忠進', 'A', 'L02-102', 60, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '一', '7,8', '04,05,11', '1、認識現代文學的發展與理論2、培養析賞現代文學的興趣3、提昇析賞現代文學的能力4、指導寫作現代文學寫作5、提升人文素養變化氣質'),
(34, 'A204', '應用文習作', 'LI', '陳猷青', 'A', 'B01-106', 57, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '四', '5,6', '04', '(一)課程內容的專業範疇說明：描述本課程的專業向度本課程旨在引導學員了解並學習現代社會常用之應用文書。實用中文不同於純文學之寫作賞析，而著眼於實用，是平日生活中表情達意的工具，並且廣泛運用於當今社會及各類型職場上，可說是現代公民必備的基本能力。本課程擬藉由理論之導引、範例之簡介，並以實用為原則，以訓練學生撰寫技法，使其除具備「實用中文寫作能力」、「語言表達能力」等，並且嘗試達到更臻美善的境界，對於未來無論從事學術研究，或進入職場領域，均能得心應手，靈活運用。 (二)與校核心能力的關係： 本課程係本校通識教育正式課程規劃中，博雅通識課程：「人文科學」子類下的一門，其所欲回應校訂「基本素養」指標為「人文素養」，所欲成就學子的能力為「知識力」，亦即「對學生具備熟習社會應用文書的期許」。 (三)與通識中心核心能力的關係： 對照於本校通識課程核心能力的養成設定，本課程希望能達成以下幾點具體目標，養成學子相關的能力： 1.積極態度與團隊合作 (1)能了解團隊與個人之分際，以及扮演之角色。 (2)能積極參與團隊，共同進行論題、論點之思考與批判。 (3)能在議題研究進行中，主動協助組員進行思考與批判。 2.組織、規劃與實踐 (1)能對論題與論點之性質進行規劃與預訂進度，並予執行。 (2)能依論題進行需要的資訊與協調人力和資源的整合。 (3)能按照計畫實施，並進行反思與修訂，激勵成員完成計畫。 3.獨立思考與解決問題 (1)能對論題與論點進行批判性思考。 (2)能對論題與論點進行必要的檢證與考察。 (3)能在對議題進行研究之後，提出自己的見解。 4.運用科技與資訊 (1) 能有效運用數位工具進行學習。 (2) 能有效運用數位工具展現所學。 5.此外在「生涯規劃與終身學習」、「探索自我與發展潛力」、「鑑賞表現與創新」等核心能力，在教學設計與學習成果的規劃中亦有相當的著墨。'),
(35, 'A213', '田野調查', 'LI', '翁烔慶', 'A', 'B01-110', 40, NULL, 3, 1, '2', 40, '114', 'A', '', '選', NULL, NULL, NULL, 0, '四', '5,6, 7', '03,04,11', '◎課程內容的專業範疇說明： ●課程引導學生學習獨立思考與團隊精神，符合國立高雄大學【核心通識六大向度】 ：「美學素養、公民素養、文化素養、倫理素養」，藉由課程的移地教學，認識社區各種層面文化與美學。過去對於臺灣常民文化和社區美學的認識，大都只限於課本圖說。希望能藉由本通識課程，帶領學子實地走近田野調查，進行社區文化美學的體驗學習。 ●本課程以臺灣社區美學和營造的狀況，進行場域實踐的思考和比較，並取國外社區營造案例經驗，增進學生對於臺灣社區文化美學營造與農村再生和地方創生的基本素養，並期許學生對於臺灣社區文化與世界接軌的地球村的雛型概念。 ●本課程【田野調查】課程，落實「走出校園，走進社區」找尋在地人文歷史足跡的教室內與戶外實作教學。歷年學期教案，以選擇就近在高雄大學鄰近社區作為教學場所，諸如：藍田里（含藍田里段後勁溪流域、謝、林老厝、仁壽宮看碑刻姓氏聚落的發展）、援中港、蚵子寮（漁業、聚落、宗族、寺廟的發展）以及鳳山舊城（典故與實地田野調查）、蓮池潭（崇聖祠看古碑）、高捷南岡山沿線文化景觀至鹽埕舊商暨高雄市歷史博物館等踏采（橋頭糖廠製糖設備解說、鹽埕區舊商圈觀察）、旗津半島常民文化觀察。都是本課程歷年的教學案例。課程最終期許培養符合校定核心能力「知識力、社會力、品格力」。'),
(36, 'A216', '籤詩文學與寺廟文化', 'LI', '翁烔慶', 'A', 'B01-110', 57, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '四', '3,4', '03,04,05', '㈠課程內容的專業範疇說明：描述本課程的專業向度本課程將引導學生瞭解籤詩文學與寺廟文化融合過程，並學習尊重民間多元文化的傳播以及培養獨立思考和判斷的精神。籤詩的內容，包羅萬象，自古即有從歷史人物、故事情節、天候、植物等面向來創造籤詩文學的民間文化。至今，籤詩的趣味也幫助許多人在生活的應用，無論在升學、求職、商場等方面的指點迷津、以及趨吉避凶的求占應用 ，相信是許多人有過的生活經驗。 本課程將帶領學生，將籤詩文學延伸自閩、粵地區，瞭解現有民間流傳的籤詩，透過早期先民的遷徙，順勢將閩、粵各地神明分靈來臺供奉，後續衍生在臺灣民間籤詩文學與寺廟文化的發展，是文學也是文化的一種融合。希望透過本課程，讓學生瞭解民間籤詩文化美學的學習與體驗。本課程也將藉由籤詩文學內涵與意義，以及民間寺廟文化美學的結合做一思考和比較，導正學生將籤詩文化以「誠信」而不「迷信」的文學面向；除了讓學生增加對於臺灣民間文化和文學欣賞的素養，亦能增進學子對於臺灣社會多元文化與世界文化接軌的概念。 ㈡與校核心能力的關係： 本課程為本校通識教育正式課程的規劃，以「人文素養」讓學子學習「美學素養」向度的「知識力」。以「公民素養」讓學子學習「文化素養」向度的「社會力」。期許本課程能讓學子具備「探索自我、發展潛能、培養獨立思考與解決問題」的基本能力。 ㈢與通識中心核心能力的關係： 希望透過本課程的學習，能提升學子的觀察力和適應力的學習，期許完成本通識課程。 了解臺灣民間多元社會文化的融合。 從臺灣民間文化與世界融合，擴展多元文化的國際視野。 從臺灣民間文學和籤詩文化來探討歷史與文化變遷。 2.尊重文化與倫理關懷 學習欣賞不同籤詩文學的意涵。 學習尊重多元場域的文化融合。 學習關懷民間籤詩文化和倫理的保存。 3.獨立思考與解決問題 對籤詩與典故進行鼓勵性的正面思考。 對籤詩與內容進行藝術性的文學欣賞。 對籤詩文化意涵，提出自己論述與應用。 ㈣列舉最主要相關的核心能力項目，及其預期成效，需與後面的檢核規劃一致從校訓「博學」的「人文素養」核心培養「思維方法」和「文化素養」：在「文學欣賞 」方面，希望學生能透過籤詩文學來「鑑賞、表現與創新」，以及從中學習「獨立思考與解決問題」的能力，培養「組織、規劃與實踐」與「積極與團隊合作」的態度並間接學習「探索自我與發展潛能」和「生涯規劃與終身學習」的預期，期待學生不管是在學或就業，能讓自己提升文化素養。 ㈤列舉次要相關的核心能力項目，簡單說明從校訓「弘毅」的「公民素養」核心培養：在「文化素養」方面，學習如何探索臺灣民間美學，從籤詩文學角度學習並尊重臺灣民間多元文化與全球化的廣度。'),
(37, 'A219', '在地知識與文化', 'LI', '王和安', 'A', 'L01-103', 39, NULL, 2, 1, '2', 40, '114', 'A', '', '選', NULL, NULL, NULL, 0, '二', '5,6', '11,10,01', '1、首先，介紹在地文化的性質，包含有形的與無形的，有形的如古蹟、契約、建築；無形的為社區生活的共同記憶、人類文化文動等。 2、其次，探訪社區與信仰中心，現今不少社區多已發展出具有社區特色的「地方知識學」；藉由社區參與的過程中，讓學生了解鄉土文化對於地方的認知與想像。 3、再者，培養學生在參與探索在地文化的過程中，藉由跨域視野訓練，以豐富在地知識與文化的意義及詮釋。 4、所謂的「在地文化」，即為地方或社區的歷史或歷史文化、人群活動，乃至於共同的歷史記憶，如何轉化成為對於鄉土、社區是一個有意義、有價值的核心。 5、注重如何藉由探索的在地文化，在社區參與、了解在地特色的過程中，以累積並強化「在地知識」的特性，以及它們對於社區的價值。'),
(38, 'A343', '人生哲學', 'LI', '蕭愛蓉', 'A', 'B01-107', 61, NULL, 2, 1, '2', 61, '114', 'A', '', '選', NULL, NULL, NULL, 0, '二', '3,4', '04,03,16', '本課程以「生命、生活、生死」作為討論範疇，結合東西方思想闡述的生命哲學、生活智慧進行探討吾人生活裡必然會面對的生命課題。一方面了解人生各方面議題的相關哲學見解，另一方面透過哲學理論引導學生觀照自我、省察生活，並思考生死課題蘊含的超越智慧。'),
(39, 'A345', '基督宗教的生命教育', 'LI', '蔡仁傑', 'A', 'B01-106', 60, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '一', '3,4', '16,05,17', '一、課程內容的專業範疇說明：描述本課程的專業向度本課程將針對「生命」的重要主題，諸如：面對人生抉擇時的態度（諸如：生老病死、苦難與祝福、捨與得之抉擇、強弱成敗之迷惘、性與婚姻）、生命的責任與義務、…等，提出基督教的看法與教導。課堂上將經由主題探討，與指定讀物、影片之感動，啟發內心之思弁與抉擇。教導學生在探討生命之意義與價值時，能建立「正確的價值觀、清楚的認知、明確的態度」，進而幫助學生「不至於後悔」。 此課程之專業向度分別如下： 1、思維方法：啟發並改變學生思維方式，不再是以「眼前、物質利益」為追求重點；而學會以更超然的「神(哲)學態度」與嚴謹的「邏輯、論證」方式，面對人生的抉擇。 2、公民與文化素養：對人生與人群(社會)有更大的「愛心與包容力」。 ◎ 例如：對「同性戀、變性」能以更「同理心」的「愛」與他們相處，而非「歧視、排斥、閃躲」。 ◎ 例如：對「年老者、身心障礙者、臨終者與其親友」能有更多「愛心、耐心」，幫助扶持、安慰他們。 3、倫理素養：不僅在「核心課程中所列舉之5種倫理」，更在「人與人、人與上帝」之倫理中，皆能以「合宜的態度」相應。 ◎ 例如：在「捨與得」之抉擇中，不再「只求自己的益處」，而置各項倫理於無物；反倒更能「顧及別人的感受與益處」。(＊『聖經』哥林多前書十：24) 4、科學素養：此課程確較偏重「宗教、倫理、社會」的探討，但仍需要具備一定的科學常識基礎才可。 ◎ 例如：在關懷「生與死」的課題上，就需要配合對醫學、生理學、心理學、宗教學、社會福利制度等知識，方能達到更深沉的關懷。 二、與校定核心能力的關係： 1、知識力：對基督宗教有基本的正確認知，不至因不瞭解而斷然否定其正面且積極的教導。 2、社會力：於思索生命主題之精義，以及「自-他(社會)」在人生中，相互影響之因果關係時，能有一明確的準繩。 3、品格力：基於內心深刻之思弁，對各主題建立合乎倫理、道德、宗教之觀念。 4、創造力：在人生實踐中，能提供明確的原則與價值觀。當面對各主題之關鍵抉擇時刻，能以不執著且富創造力之思維，活出「積極且蒙福」的人生。 三、與通識中心核心能力的關係： 對照於本校通識課程核心能力的養成設定，本課程希望能達成以下幾點具體目標，養成學子相關的能力： 1、探索自我與發展潛能透過本課程所設計之各主題的探討，可以幫助學生探索自己；進而激起內在的潛能，使自己的生命更豐盛。 ◎ 例如：對「生與死」的探討，可更了解自己「內心深層的恐懼」，進而激起「克服」此恐懼的力量。 2、獨立思考與解決問題由於本課程之各主題都在探索「生命、價值、倫理」等課題。而這些課題的答案，常會因「時代的變遷、社會主流意識、年齡的增長、…」 而模糊，甚至改變。故此課程用意在「啟發、引導」學生 「獨立思索、關心」這些課題，以免「人云亦云，隨波逐流，毫無主見」；如此或能跳脫窠臼困境， 找到解決問題之道。 3、積極態度與團隊合作課程教導對生命有「積極正向的看法」，了解人生的目的不應僅在追求個人最後獨得的「金牌」， 乃在其「過程」的意義。如同使徒保羅積極地「向著標竿直跑」(＊『聖經』腓力比書三：14)，當他與同工團隊一起「打完美好的仗、跑完當跑的路」後，他清楚知道，會有「公義的冠冕」為他存留(＊『聖經』提摩太前書四：7-8)。故，以「積極態度」在過程中建立與「他人」的「良性合作、 互動關係」，正是「擁有幸福人生、贏得人生獎盃」之道。 4、尊重生態與倫理關懷基督教相信「一切都是上帝的創造」：宇宙大自然諸生態是如此，人與人際社會更是如此。所以， 在基督教倫理學中，「尊重生態」與「倫理關懷」乃不可忽視，必須深刻思考與教導、實踐的主題。當然，「基督宗教的生命教育」豈不更應強調此兩者的重要性! 5、鑑賞、表現與創新欣賞並尊重世上各種「個性、性向、族群」的人；對他人會誠心且合宜的表現出內心的感動與關懷；對人生所有的現況，不論「順逆、禍福」，都能以「創新、正向」的方式面對，使人生充滿 「驚喜與色彩」。 6、此外在教學設計與學習成果的規劃中，對「運用科技與資訊」、「生涯規劃與終身學習」、「多元文化與國際視野」、「組織、規劃與實踐」等各項核心能力，亦有一定的延伸探討。 四、 列舉最主要相關的核心能力項目，及其預期成效，需與後面的檢核規劃一致 ◎ 核心能力項目1：探索自我與發展潛能： ＊預期成效： 1.對「生命意義」與「生命力量」有更新且更正確的認知。 2.能更真誠地面對自己的「內心負面的因子」，諸如：欲求、恐懼、性向、驕傲、…等。並進而將之導向更積極正面的方向。 3.對自己所擁有的「正向潛能」有清楚的認知，並更有信心去發展、運用此力量。 ◎ 核心能力項目2：尊重生態與倫理關懷 ＊預期成效： 1.從各課程主題皆為「兩相對立」的設計中，理解生態間的複雜與鏈結，亦須具備正反對立的配搭，方得完整。 2.進而理解物種存在之間息息相關，必須平衡尊重所有物種生態，不可偏頗。 3.在關懷老人的服務體驗中，能思考社會資源分配背後所隱藏的倫理問題。 五、列舉次要相關的核心能力項目，簡單說明 ◎ 次要相關的核心能力項目1：培養獨立思考與解決問題的能力 ＊簡介與預期成效： 1. 能對與「生命」相關論題與論點進行「批判性思考」，並進行「必要的檢證與考察」。 2. 在對議題進行執中不偏的研究後，縱使與眾人的見解相牴觸，也不畏提出自己的結論；並勇敢坦然接受討論的挑戰。 ◎ 次要相關的核心能力項目2：積極態度與團隊合作 ＊簡介與預期成效： 1.能秉持良善積極的態度經由周詳的規劃與認真實踐的過程，完成志工服務之使命。 2.由實踐中體驗學習「積極態度」與「團隊合作」的精神。'),
(40, 'A374', '古典音樂導聆', 'LI', '蔡麗芬', 'A', 'L01-103', 54, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '四', '5,6', '04,17,03', '1. 引導學生透過古典音樂，豐富及培養學生的感受力及鑑賞能力。(知識) 2. 以理性分析為出發點，找出音樂的語彙。(技能) 3. 最主要目標為啟發學生音樂欣賞能力。(態度) 4. 在音樂世界中學習音樂生活、豐富人生。(其他)'),
(41, 'A424', '為你的想法發聲：批判思考寫作', 'LI', '蔡郁焄', 'A', 'M01-206', 40, NULL, 2, 1, '2', 40, '114', 'A', '', '選', NULL, NULL, NULL, 0, '一', '7,8', '04,10,16', '這不是一門教你「把文章寫漂亮」的課，這是一門教你「如何思考」的課。 本課程採用美國經典教材TheBedfordReader，將寫作視為一種思考的工具。我們將學習如何運用敘事、比較、因果、定義等「修辭模式」來拆解複雜議題，並建構有力的觀點。本課程的核心精神是「好文章是改出來的」。不只看重最終產出，更看重修改歷程。你將建立一份「學習歷程檔案」，證明你如何運用課堂所學，將一篇普通的初稿，透過邏輯診斷與修辭調整，進化為強而有力的論證。 這門課的教學目標如下： 一、覺察與描述： 能運用感官細節將抽象概念具象化，避免空泛論述。 二、分析與評估： 能運用比較與分類等工具，對議題進行多維度分析。 三、邏輯與論證： 能建構嚴謹的因果推論，並提出具說服力的論證。 四、後設認知與修正： 能使用「檢核表」自我診斷，並具備自我修正的能力。'),
(42, 'A497', '台灣之流行音樂與社會變遷', 'LI', '陳怡靜', 'A', 'L01-103', 60, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '五', '5,6', '04', '流行音樂雖被歸屬為次文化之藝術, 卻與人们生活息息相關,作曲作詞者常將當時的人,事,物甚至於生活環境..等融入音樂創作中,藉由社會的變遷來探討對流行音樂影響,由不同年代的社會背景來探討台灣流行音樂的類型與風格之演變'),
(43, 'A634', '視覺藝術概論', 'LI', '林殷齊', 'A', 'L02-201', 23, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '四', '5,6', '04,10,17', '現在是個大量視覺傳播資訊的時代，3C產品的氾濫，電視、電影以及動玩帶來的視覺饗宴，充斥整個年輕世代的日常生活。這堂課主要設計是，藉由視覺藝術的概念，帶領學生思考視覺觀看的複雜性與重要性，學習如何識讀進而尊重社會文化差異，關懷社會議題，甚而更了解自己。盼引領學生反思，自己該如何建立自我的能力，進而辨識或識讀這樣的大量媒體視覺資訊。 於是教學目的是藉由視覺藝術符號激盪學生的思考，發展其潛在的創造力，銳化其對視覺藝術的觀看，學習詮釋、分析視覺藝術背後帶來的議題批判能力，嗅出視覺藝術符號、社會之間的圖像脈絡意義，並清楚認識視覺藝術所帶出的生活脈絡思考。'),
(44, 'A714', '戲曲藝術入門與賞析', 'LI', '王海玲', 'A', 'B01-107', 51, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '五', '8,9', '04,16,17', '1.培養學生對傳統戲曲文化的認知。 2.學習基礎戲曲身段、基本功之技能。 3.培養學生欣賞傳統戲曲藝術之能力。 4.引發學生參與藝文活動之興趣，以提升人文素養。'),
(45, 'A810', '電影文學與人生', 'LI', '高美芸', 'A', 'L01-103', 60, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '四', '7,8', '03,04,16', '文學與電影兩者具借鑒觀摩之效、相輔相成之妙、互通有無之功。然而，兩者也有一定的分別。文學以文字展現天地宇宙與無限時空，而電影則以聲影畫面馳騁古往今來，光怪陸離。兩者同樣可以狀物描人，抒情寫意，論道敘事，在文學技巧和電影表現手法中，不難發現它們之間的聯繫。電影歷史中，大量的文學作品被改編成膾炙人口的經典名片，而不少電影表現手法也被文學家融入文學創作之中，其間的保留、整理、刪減與改變，正反映了電影對文學的繼承與突變。而電影語言(表現手法)的養份也被現代詩歌、小說吸收，在剪裁、用字上，著重凸出現場畫面感和立體效果。本課程藉著欣賞具有文學內涵的藝術電影，進而培養具有人文思考與文化內涵的認識與感知能力。 二十一世紀顯然是影音多媒體擅場的新世代。即便如此，文字仍具有不可取代的特性，對於表述人生、記錄文化具有「關鍵少數」的地位，不容忽視。本課程嘗試以電影名片、文學作品，闡釋文學之於電影，如何會通與轉化，以指引非文學與電影專業科系學生，能閱讀分析構成文學與電影美學的語言為目標。並嘗試以電影為獨立之文學藝術作品，進行解讀與欣賞。教學內容著重於閱讀文學及討論電影，以電影創意、攝影、鏡頭、燈光、音效、音樂等多媒體語言的角度，比較文學作品之閱讀觀點，引導學生深入思考，並以較寛廣的視野，學習欣賞文學與電影。寄望學子從電影欣賞及文學作品的閱讀中，尋繹人生哲學思維，藉以達到身心安頓的目標，迎向多角度經營的創意人生。'),
(46, 'A842', '台灣原住民族文化', 'LI', '林富水', 'A', 'L02-102', 60, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '三', '5,6', '17,11,10', '一、本課程期望以深入淺出的方式，以台灣原住民十六族(不含平埔族)為主要範疇，藉著課程講解、影片、文字及學生親自參文化分享，寓教於樂的話劇與舞蹈，產生文化理解，培育關懷原住民族的知識力、社會力、品格力及創造力。 二、本課程實務上的目標，透過學生上台報告，期待培養學生對台灣原住民文化或景點的導覽解說能力。 三、本課程精神上的目標，期待在多元文化的台灣社會，期使漢民族與國際各民族的多元學習與善解包容原住民文化，創造台灣社會穩定與共存共榮的意願與能力。(台灣原住民族豐富的歷史和文化資源，在全球化與兩岸關係的發展中，展現台灣文化中最具特色的文化呈現之一，隨著全球的政經發展與台灣主流文化中的漢化，儘管本土化的熱潮，原住民文化在強勢文化的環境中漸漸流於產業觀光形式，侵蝕文化的本質特性。原住民的部落看似正視，但原住民都市化或是經濟依賴中的社會流動，依賴部落文化土壤外，仍必須依賴學校教育紮根與發揚。) 四、安排專題報告，使同學們從“臺灣原住民族文化”知識接收者 (PassiveInfo. Consumer) 轉化為主動學習者 (ActiveLearner)。讓同學們在臺灣原住民族文化”課堂學習更有生產力，合作搜集資料與整理ppt報告內容，能上台歷練講述的壓力體驗與能力展現。老師可觀察學生應用原住民族文化的知識能力，視情況給學生差異化的協助，教室中的主角從教師變成學生，老師成為幕後的導演與助手，學生從報告中展現能力而增長潛能與激發信心。'),
(47, 'A844', '台灣原住民族藝術文化', 'LI', '陳海雲 業界教師', 'A', 'C02-108', 60, NULL, 2, 1, '2', 60, '114', 'A', '課程相關問題請聯繫<學務處原民中心>', '選', NULL, NULL, NULL, 0, '二', '10,11', '04,10,08', '教學目標： (一) 原住民族語言文化學習為原住民族終身教育的重點，因應社會能力認證之培養。 (二) 認識台灣原住民族語言歷史文化。 (三) 透過學習原住民族語言，增加族語學習管道、促進學習動機及拓展族語使用場域。 (四) 加強族語認證通過率。 ★上課時段：每週二18：20~20：05 ★上課地點：C108、C106、C104理學院教室'),
(48, 'A854', '台灣多元族群的文化探索', 'LI', '楊書濠', 'A', 'L02-101', 19, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '一', '8,9', '10,11,16', '1.能說明台灣主要族群（原住民、閩南人、客家人、外省人等）的歷史背景與文化特徵。 2.能分析台灣歷史上不同政權如何影響族群分布與社會結構。 3.能舉例說明族群間的文化互動與融合現象。 4.能針對當代族群議題（如文化保存、族群歧視、多語政策等）提出觀察與反思。 5.能展現對不同族群文化的尊重與包容，具備同理心與溝通能力。 6.能參與討論與小組合作，表達對台灣多元文化的理解與看法。 透過本課程的學習，學生將能建立起對台灣族群歷史的整體認識，並在未來社會互動中實踐多元與共融的價值。'),
(49, 'B013', '電影中的音樂媒介', 'LI', '陳怡靜', 'A', 'L01-103', 60, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '五', '3,4', '04', '1. 藉由故事性的影像畫面,引導生更加融入音樂的內涵與本質2.藉由電影視覺性的感官來加強聽覺感官3. 藉由”看” 電影的趣味來引發學生們感受音樂在[電影]的重要性4.體會八大藝術(音樂, 繪畫, 雕刻, 建築, 文學, 舞蹈, 戲劇與電影)中, 音樂與電影呼應之美5.感受不同領域的藝術互相融合,可使彼此的作品更加完美'),
(50, 'B014', '從巴洛克到搖滾樂', 'LI', '陳怡靜', 'A', 'L01-103', 60, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '五', '1,2', '04', '引導學生認識西方音樂之古典, 爵士到流行音樂的變遷�z領略音樂作品在創作當時的文化與社會背景藉由不同年代與風格的音樂作品介紹,引領學生建立欣賞音樂的基本入門知識, 讓聆聽音樂融入日常生活, 達到音樂生活化, 生活音樂化'),
(51, 'B015', '電影音樂欣賞', 'LI', '蔡麗芬', 'A', 'L01-103', 60, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '四', '3,4', '04,03,17', '1. 引導學生透過音樂來記憶電影，進而豐富及培養學生的感受力及鑑賞能力。(知識) 2. 以理性分析為出發點，找出音樂與電影的關聯性。(技能) 3. 最主要目標為啟發學生音樂欣賞能力，特別是與電影情節、影像、結構如何與相關音樂之聯結與契合。(態度) 4. 在電影世界中學習音樂生活、豐富人生。(其他)'),
(52, 'B032', '日本社會與語言', 'LI', '蔡仁傑', 'A', 'B01-106', 60, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '一', '1,2', '17,16,04', '(一)課程內容的專業範疇說明：描述本課程的專業向度現代日本之社會風貌與流行時尚對台灣社會，尤其年輕人有極大吸引力。 然而往往只羨慕、模仿其表象，卻對其歷史、社會現況、精神內涵等，一知半解。本課程將從日本語文(例:文學、影片、演歌…)及社會現象(例 :半澤直樹的加倍奉還、草食男、宅男…)探討大學生應該認識的日本社會、文化之精神內涵;並與台灣的社會現象作連結比較分析。故，透過本課程，將可加強對日本社會現象的理解與詮釋;並進而增進分析、組織、 規劃與實踐的能力，增進自己的多元文化與國際視野。 ※課程目標： (1) 能以日語「聽、說」數句常用之「生活用語」及「耳熟能詳之名詞」。 (2) 對日本文化精神之內涵，諸如：武士道、心、美…等，因認知而感動。 (3) 習得日本「歷史」「風土、民情」及「食衣住行育樂」等之基本知識。 (4) 啟發日後對日本更進一步探討之好奇心。 (5)建立日後前往日本留學、旅遊之「自信心」。 (二)與校核心能力的關係： 本課程係本校通識教育正式課程規劃中，博雅通識課程：「人文科學」子類下的一門，其所欲回應校訂「基本素養」指標為「文化及公民素養」，所欲成就學子的能力為「社會力」，亦即「對學生具備社會責任的期許」。 (三)與通識中心核心能力的關係： 對照於本校通識課程核心能力的養成設定，本課程希望能達成以下幾點具體目標，養成學子相關的能力： 1. 多元文化與國際視野 (1)能從國際視野觀察日本社會的發展 (2)能從日本社會的角度，思考臺灣對國際社會可能的貢獻 (3)能從多元文化的角度，檢討日本社會問題2. 培養獨立思考與解決問題的能力 (1)能對日本社會與論點進行批判性思考。 (2)能對日本社會論點進行必要的檢證與考察。 (3)能在對議題進行研究之後，提出自己的見解。 3. 生涯規劃與終身學習 (1)能對日本社會論題與論點進行批判性思考。 (2)能對日本社會論題與論點進行必要的檢證與考察。 (3)能在對日本社會議題進行研究之後，提出自己的見解。 此外在「尊重生態與倫理關懷」、「組織、規劃與實踐」、「運用科技與資訊」、「積極態度與團隊合作」、「探索自我與發展潛力」等核心能力，在教學設計與學習成果的規劃中亦有相當的著墨。'),
(53, 'B068', '初級日語會話(二)', 'LI', '錢秋茜', 'A', 'B01-105', 40, NULL, 2, 1, '2', 40, '114', 'A', '東語系日文組；或以日語為母語者請勿選修', '選', NULL, NULL, NULL, 0, '五', '3,4', '04,08,17', '• 本課程須具備50音基礎 • 以深入淺出的方式培養自我學習之方法，鼓勵開口說日語，達到聽說讀寫的基礎 • 透過課程安排與分享，以活用有趣的上課方式，增加學生對日本語言與文化的興趣與認識，提升學生第二外語能力'),
(54, 'B069', '職場英文聽讀訓練', 'LI', '王靜嫻', 'A', 'B01-103', 40, NULL, 2, 1, '2', 40, '114', 'A', '西語系，或母語為英語者請勿選修。', '選', NULL, NULL, NULL, 0, '一', '7,8', '04,08', '1Toimprovestudents\' test-takingskills2.Tohelpstudentsbuildtheirself-studyability3.Toenhancestudents\' Englishspeakingability4. Toenhancestudents’ theabilityofreadingandspeakingEnglishnews'),
(55, 'B070', '全民英檢準備班', 'LI', '陳信智', 'A', 'B01-110', 40, NULL, 2, 1, '2', 40, '114', 'A', '西語系，或母語為英語者請勿選修。', '選', NULL, NULL, NULL, 0, '五', '5,6', '04,17,08', '本課程以台灣全民英檢考試為主軸,透過重點文法,閱讀,聽力,與單字的介紹與練習,同時涵蓋其他相關檢測考試,同學修完課程後能通過相關檢測考試'),
(56, 'B086', '基礎法語(二)', 'LI', '歐陽蒨', 'A', 'L02-103', 39, NULL, 2, 1, '2', 40, '114', 'A', '', '選', NULL, NULL, NULL, 0, '一', '5,6', '17,04,08', '透過基礎語言的學習,包括發音、字母、基礎文法與情境句型等,讓學生能聽說讀寫簡單法語。並藉由語言的學習，認識法國及其文化。'),
(57, 'B087', '工商英文聽力和閱讀訓練', 'LI', '王淑雱', 'A', 'C02-107', 25, NULL, 2, 1, '2', 61, '114', 'A', '限理學院及西語系同學選修', '選', NULL, NULL, NULL, 0, '五', '5,6', '08', 'ThiscourseisdesignedtoorientstudentstothecontemporaryframeworksandmethodologiesoftheNewTOEICexamination. Beyondmeretestfamiliarity, thecurriculumaimstobolsterlinguisticproficiencywithinprofessionalcontextsandrefinethestrategiccompetenciesessentialforstandardizedassessmentsuccessandeffectiveworkplacecommunication. 本課程旨在協助學生熟悉新制多益（NewTOEIC）測驗的當代架構與評測方法。除提升對題型的掌握度外，課程目標更在於強化學生在職場環境中的語言應用能力，並精進其在標準化測驗中取得佳績所需的策略素養，以利於職場專業溝通。 　'),
(58, 'B088', '旅遊商務英文', 'LI', '楊淑華', 'A', 'B01-106', 40, NULL, 2, 1, '2', 40, '114', 'A', '西語系，或母語為英語者請勿選修。', '選', NULL, NULL, NULL, 0, '一', '9,10', '04', 'Thiscourseaimstoequipstudentswiththelanguageskillsnecessarytoeffectivelycommunicateinvarioustourismorbusiness-relatedscenarioswithaspecialfocusontourism, enhancingtheirabilitytointeractconfidentlyandprofessionallyinthetourismindustry. Specializedvocabularyandconversationskillswillbeemphasizedbyintegratingessentialthemes, includinghotelreservationsandcheck-inprocedures, restaurantservices, transportation, airportscenarios, aswellasbookingflightticketsandnavigatingairports. Bytheendofthiscourse, studentswillhaveexpandedtheirvocabularyandimprovedtheirEnglishconversationalskillswithinthecontextoftourismandbusiness.'),
(59, 'B089', '運動飲食英文', 'LI', '許建華', 'A', 'B01-107', 40, NULL, 2, 1, '2', 40, '114', 'A', '西語系，或母語為英語者請勿選修。', '選', NULL, NULL, NULL, 0, '四', '7,8', '03,04,17', 'ToreachthebetterEnglishleveloflisteningandreadingbythetopicsofsportandfood * 請先加入老師的LINE以方便連絡ID: jeffcarlosxu並留言告知選修本科目以便被加入本班的群組&FB社團“Sport&Food養生食療”課程連結將貼在LINE群組請先加入若於課程期間將以Googlemeet進行課程，並將當日連結網貼於本班LINE群組或＆FB社團'),
(60, 'B090', '英語口語表達', 'LI', '歐素雯', 'A', 'B01-108', 25, NULL, 2, 1, '2', 40, '114', 'A', '西語系，或母語為英語者請勿選修。', '選', NULL, NULL, NULL, 0, '三', '3,4', '10,04,17', '1. TotrainthestudentstoexpressthemselvesbetterinEnglish. 2. Tobuildupthestudents\' confidenceinoralcommunication. 3. ToprovidetheopportunityandfamiliarizethestudentstoengageinmeaningfulEnglishconversation. 4. Thestudentsmaybemoreawareofdifferentcultures'),
(61, 'B201', '初級越南語(一)', 'LI', '范氏香蘭', 'A', 'L02-106', 40, NULL, 2, 1, '2', 40, '114', 'A', '東語系越語組，或母語為越語者請勿選修', '選', NULL, NULL, NULL, 0, '二', '3,4', '17', '1.正確唸出、寫出越南語文字，及訓練以培養初級越南語文法的能力. 2.訓練以培養初級越南語文法的能力. 3.加強聽講練習. 4.增加語彙及造句能力.'),
(62, 'B202', '初級越南語(二)', 'LI', '范氏香蘭', 'A', 'M01-105', 40, NULL, 2, 1, '2', 40, '114', 'A', '東語系越語組，或母語為越語者請勿選修。', '選', NULL, NULL, NULL, 0, '二', '5,6', '17', '1.正確唸出、寫出越南語文字，及訓練以培養初級越南語文法的能力. 2.訓練以培養初級越南語文法的能力. 3.加強聽講練習. 4.增加語彙及造句能力.'),
(63, 'B213', '初級泰語(二)', 'LI', '潘婉玲', 'A', 'M01-205', 35, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '四', '5,6', '', '使學員們能夠用簡單的泰語進行溝通,並且可以拼寫泰文字母,進而對泰國文化有更深入的了解'),
(64, 'B214', '商用泰語', 'LI', '潘婉玲', 'A', 'L02-106', 58, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '四', '7,8', '', '本課程旨在培養學生於商業與職場情境中正確且得體地運用泰語進行溝通之能力，增進商用泰語詞彙與句型之掌握，並深化對泰國商業文化與職場禮儀之理解，以提升實務應用能力與跨文化溝通素養。'),
(65, 'A022', '探索地球', 'SC', '周孟麟', 'A', 'L02-108', 25, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '二', '3,4', '13,11,03', '人類生存在地球上，需要對於孕育生命及提供我們生活環境的母體有認識，才能珍惜自然界提供於我們的一切，培養永續的觀念，才能真正落實環境保護的工作，本課程所要達成的目標： 1.使學生能具備地球環境科學的重要基本知識 2.使學生具備環境觀察之敏感度3.使學生具備防災概念4.使學生能對地球科學相關議題產生興趣與學習意願'),
(66, 'A141', '基因工程與生活', 'SC', '葛孟杰', 'A', 'C02-102', 60, NULL, 2, 1, '2', 60, '114', 'A', '生科系請勿選修', '選', NULL, NULL, NULL, 0, '三', '5,6', '02,03', '讓非生科系學生了解基因工程與生活的關聯性. 基因工程與生活 (星期二) · 上午10:00 - 下午12:00如何加入GoogleMeet會議視訊通話連結：https://meet.google.com/coj-cehe-cnu'),
(67, 'A142', '生活中的數學', 'SC', '張雲清', 'A', 'L02-103', 19, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '二', '3,4', '17,04,11', '生活中處處可見數學的應用，像是每天關心的天氣預測、天天在用的加減乘除、科幻電影中的特效，流行服裝設計、醫學檢測或手術工具，甚至桌球、羽球、…等運動項目，都與數學息息相關並扎實地影響著我們的生活。因此本課程將幫助同學了解這些生活層面與數學密不可分的關係，我們也會從中看到數學對於過去人類歷史的進程與未來的重大影響趨勢。'),
(68, 'A144', '大數據初探', 'SC', '張雲清', 'A', 'M01-104', 23, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '二', '5,6', '17,04,11', '人工智慧與大數據分析為當今的極為重要及熱門的顯學，正全方位地引領著我們的未來生活，因此本課程將幫助同學了解相關的最新發展，比如智慧家庭、機器人、虛擬實境與大數據分析…等最有前景的應用。在瞭解計算機與科技背後的原理如何感知與改變世界後，我們便能看到計算機是可以從數據中「學習」的，而人工智慧開發人員也致力於創建機器與人類產生自然互動的代理，我們也會看到人工智慧將如何對社會產生積極和消極的影響。'),
(69, 'A145', '數學x機器人：進擊的大學生', 'SC', '吳志宏 張志鴻', 'A', 'C02-105', 36, NULL, 3, 1, '2', 40, '114', 'A', '', '選', NULL, NULL, NULL, 0, '三', '5,6, 7', '04', '本課程以協同合作、互惠、尊重多元差異、學習為基礎、社會正義為焦點」等特質為基礎，以準備、服務、反思、慶賀等學習歷程，以高大周邊社區國教端學校為服務場域，以科學教育、數學教育議題為核心，對接SDG4-良質教育，由授課教師引領修課學生運用專業至服務場域進行實作，以培養學生關懷社會及服務人群的情操，並促進公民責任之實踐。本課程執行目標是培養大學生服務的熱忱，關懷高大周邊社區國教端學校學生的學習與發展，運用自身所學專長與科學、數學素養，輔導學童共學成長，進一步營造學校與社區的友善關係，實踐高大的社會責任。 合作場域：援中國小、蚵寮國小進行模式：採取類營隊方式進行，前9週課程重點在於將國小四五年級的數學課程結合mBot輪型機器人，設計營隊教案與活動，並進行行前訓練；後6週進到場域帶領營隊活動。'),
(70, 'A286', '傳統推拿整復概論', 'SC', '劉明坤', 'A', 'C02-101 其他教室', 40, NULL, 2, 1, '2', 40, '114', 'A', '第11-16周至K01-210按摩教室上課', '選', NULL, NULL, NULL, 0, '三', '10,11', '03', '本課程從易經陰陽五行學說、經絡學說、五臟六腑等中醫基礎理論開始、並輔以刮痧、拔罐之常用技巧與實例操作，治療方法從臨床觸診檢查之手感教起，介紹各種推拿手法及推拿手法的動作結構、動作原理、訓練方法、作用機理及臨床應用，對身體局部傷痛或運動和工作所造成的傷害瞭解其病因及病理，找到解決的方法，為學習推拿調理與日後從事推拿臨床工作，奠定理論與技能基礎。'),
(71, 'A293', '環境保護', 'SC', '倪麥童', 'A', 'B01-108', 60, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '二', '5,6', '13,11,12', '請加入113-2科技與社會倪麥童課程群組，Line網址:https://line.me/R/ti/g/aWrw_w2fPq 「老師的一顆心，學生的一片天。」，通識教育是『一場可帶走的盛宴』，在未來的人生，可以有相當大的幫助。我們正在實現這個夢想，希望能用我們的誠意，讓您成為我們實現夢想的夥伴，加入我們成為現代科技公民，人生多彩多姿，快樂學習。 (一)與校核心能力的關係： 本課程係本校通識教育正式課程規劃中，核心課程：「科學素養」子類下的一門，其所欲回應校訂「基本素養」指標為「科學素養」與「專業素養」，所欲成就學子的能力為「知識力」與「創造力」，除建立學生學習能力與思考能力外，同時激發學生創造之發想與實作能力。 (二)與通識中心核心能力的關係： 對照於本校通識課程核心能力的養成設定，本課程希望能達成以下幾點具體目標，養成學子相關的能力： 1.民主素養：本課程將經由全球化議題之探討，幫助學生了解全球性之規範、慣例、典章和制度，提升學生休戚與共之感受與對多元文化之認同，使其具力行民主生活所需的民主知識、態度。 2.倫理素養：沒有倫理的科學可能是空洞、主觀、武斷及有偏見的。本課程將於適合之主題課程中，佐以相關影片、文獻資料進行討論，強化學生重視且實踐「有倫理的科學」，並幫助學生從科學探索的角度找尋一種與生活價值契合的豐富美好內涵與時代精神，從中建立「高感度、高體會」之美學新概念，使其不管在哪個面向都可發展出延伸的美意與信念。 3.科學素養：本課程之主要課程設計即以建立學生科學素養為主，除自製投影片內容說明外，並配合科普讀本導讀及相關影片，引導學生藉由小組討論及簡報，進行深度科學思考，進而提升「形成科學議題」的能力及「解釋科學現象」的能力。 同時以1.「STS教學模式」以「STS教學模式」進行，提高學生的學習興趣與動機：課程以社會議題或生活中的問題為題材，藉由科學探究活動的進行，使學生可以習得相關的技能和技術，更可以科學的態度和科學的概念去尋找問題解決之道，並且從中表現出其創造力，進而提昇其學習興趣與科學素養。 2.培養學生問題解決的能力：透過問題導向學習的過程，學會如何面對生活中真實情境問題的解決方法。 3.培養高層次思考能力：透過問題導向學習的討論及與人分享的過程，學生可以培養對問題內容批判思考、創造性思考及知識整合能力，擺脫傳統的限制，可因應問題而變化解決的途徑，以產生不同類別的解答。 4.培養學生合作學習的精神及社會化協商的能力。'),
(72, 'A483', '自然保育概論', 'SC', '蘇永銘', 'A', 'B01-106', 60, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '四', '7,8', '15,14,13', '工業革命後全球因經濟快速成長，人口增加，自然資源在沒有合理規劃下，被過度利用而遭受嚴重破壞。人類除了已面臨嚴重的環境污染問題外，海岸、河口、河川地等濕地以及山坡地遭大量開發使用，使水土流失。另野生動物被濫捕與毒殺、原生珍稀動植物瀕臨絕種及其棲地遭受破壞等問題亦日趨嚴重，令人憂心。為此，健全自然資源之保育與經營管理，維護生態系之穩定，以提升全體人類生活環境品質，實為謀求地球永續發展所不可忽視的重要課題。因此本課程擬針對上述所提及之問題及相關知識，經科學的整理後，正確的傳達給學生。課程中可吸收到的基本知識，包括自然保育的基本概念、台灣的自然資源及野生動植物保育等概況。'),
(73, 'A498', '氣候變遷與永續發展', 'SC', '周孟麟', 'A', 'B01-109', 44, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '三', '3,4', '13,15,14', '本課程使學生明白「地球暖化」的現象是因為人類的經濟、產業活動造成溫室氣體增加所致。如果溫室氣體再繼續增加，最終將導致北極與南極的冰層融化、農林作物因乾旱而歉收，連動物都將無法生存。同時，氣候變遷也將以各種形式對經濟造成損失，再加上因應氣候變遷所需的費用，對世界經濟造成的影響將無法估量。 氣候變遷是一個龐大的難題，以至於連聯合國都將其列為「永續發展目標(SDGs)」之一。本課程淺顯易懂地解說這個過於龐大而複雜的問題。 追根究柢，氣候究竟是什麼？如今正如何持續變化？人類面對氣候變遷又能夠做些什麼？讓我們一起來一探究竟吧！'),
(74, 'A572', '常用藥物基本知識', 'SC', '戴秀卿', 'A', 'B01-108', 58, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '四', '10,11', '03,04,02', '一.課程內容的專業範疇說明：描述本課程的專業向度本課的目的在於提供學生對用藥的正確認知，減少醫療過程可能發生的錯誤與疏失，幫助學生掌握必要的健康知識，使學生對用藥的正確認知能有一概論性了解，進而確保自身用藥的安全與有效，進而確保自身用藥的安全與有效。 二.與校核心能力的關係：本課程係本校通識教育正式課程規劃中，符合全人教育與博雅教育之精神，並於授課大綱中導入行動導向/問題解決導向課程規劃元素，有益學子養成學子的能力為「知識力」，亦即「學會如何用藥的正確認知的能力」，以及讓學生如何落實執行才擁有健康。 三.與通識中心核心能力的關係： 對照於本校通識課程核心能力的養成設定，本課程希望能達成以下幾點具體目標，養成學子相關的能力： (一)多元文化與國際視野1.能從國際視野瞭解WHO與世界各國用藥的重要議題。 2.能從臺灣的角度，思考臺灣對用藥的概況。 3.能從多元文化的角度，檢討臺灣對用藥的問題。 (二)獨立思考與解決問題1.對論題與論點進行批判性思考，藉學生對問題認知的彼此互動提高學習興趣，使學生對用藥問題能有一概論性了解，進而尋求預防及解決之道。 2.對論題與論點進行必要的檢證與考察，對應自己與家人用藥問題。 3.對議題進行研究之後，提出自己的見解與改善。 (三)尊重生態與倫理關懷1.能思考醫療資源分配背後所隱藏的倫理問題。 2.能掌握現代化、全球化對用藥所造成的問題。 (四)生涯規劃與終身學習的能力1.健康是一切成就的基礎，故需有健康方能有成果。 2.個人身、心、社會、靈性的健康與用藥是生涯規劃與終身學習的必備條件。 此外在「組織、規劃與實踐」、「運用科技與資訊」、「積極態度與團隊合作」、「鑑賞表現與創新」、「探索自我與發展潛力」等核心能力，在教學設計與學習成果的規劃中亦有相當的著墨。 　 　 　'),
(75, 'A621', '人類生殖探秘', 'SC', '劉紹東', 'A', 'H1--106', 60, NULL, 2, 1, '2', 60, '114', 'A', '運休系同學請勿選修', '選', NULL, NULL, NULL, 0, '二', '3,4', '05', '人類男性與女性生殖系統上在解剖學，生理學，內分泌學及心理學之一般探討。'),
(76, 'A711', '健康與生活', 'SC', '戴秀卿', 'A', 'B01-108', 60, NULL, 2, 1, '2', 60, '114', 'A', '', '選', NULL, NULL, NULL, 0, '四', '8,9', '03,04,02', '方案(一) 線上授課，實體測驗/報告。 Microsoftteams連結： https://teams.microsoft.com/l/team/19%3atezttdNC2AWg1BcHIrMM1oB1yQo7ptRzMRv05i8xLB41%40thread.tacv2/conversations?groupId=92c5d9a5-2b36-4b22-886e-4e7eabac276a&tenantId=5a484953-77ef-42ec-90cf-2f4e1037ffc7 (一)課程內容的專業範疇說明：描述本課程的專業向度本課程旨在引導學子探索並提供學生基本的健康保健之道，瞭解變遷社會及醫療環境中做為現代人的健康之道以最淺顯的方式，幫助學生掌握必要的健康知識。 (二)與校核心能力的關係： 本課程係本校通識教育正式課程規劃中，符合全人教育與博雅教育之精神，並於授課大綱中導入行動導向/問題解決導向課程規劃元素，有益學子養成學子的能力為「知識力」，亦即「學會如何健康保健的能力」。 (三)與通識中心核心能力的關係： 對照於本校通識課程核心能力的養成設定，本課程希望能達成以下幾點具體目標，養成學子相關的能力： 1.多元文化與國際視野 (1)能從國際視野瞭解WHO與世界各國推動健康促進的重要議題。 (2)能從臺灣的角度，思考我國對推動健康促進的貢獻。 (3)能從多元文化的角度，檢討臺灣對推動健康促進的問題。 2.獨立思考與解決問題 (1)對論題與論點進行批判性思考，藉學生對問題認知的彼此互動提高學習興趣，使學生對自身健康問題能有一概論性了解，進而尋求預防及解決之道。 (2)對論題與論點進行必要的檢證與考察，對應自己與家人健康問題與生活型態。 (3)對議題進行研究之後，提出自己的見解與改善。 3.尊重生態與倫理關懷 (1)能思考醫療資源分配背後所隱藏的倫理問題。 (2)能掌握現代化、全球化對生態與環境所造成的問題。 4.生涯規劃與終身學習的能力 （1）健康是一切成就的基礎，故需有健康方能有成果。 （2）個人身、心、社會、靈性的健康是生涯規劃與終身學習的必備條件。 此外在「組織、規劃與實踐」、「運用科技與資訊」、「積極態度與團隊合作」、「鑑賞表現與創新」、「探索自我與發展潛力」等核心能力，在教學設計與學習成果的規劃中亦有相當的著墨。'),
(77, 'A775', '飛鏢理論與實務', 'SC', '孫美蓮', 'A', '', 40, NULL, 2, 1, '2', 40, '114', 'A', '運休大樓游泳池前集合', '選', NULL, NULL, NULL, 0, '一', '5,6', '03', '(1)學習如何提升多元運動技能，充實自我，增加就學期間生活樂趣 (2)學習有關人體運動的知識，認識體育運動的內涵、本質、目的、功能和價值 (3)學習在從事體育活動和運動競賽中，如何發展更有效率的社會互動互助行為和待人處事之道 (4)學習新興體育運動休閒產業技術及知識，利用所學增加未來就業管道'),
(78, 'A777', '飛鏢理論與實務', 'SC', '孫美蓮', 'A', '', 40, NULL, 2, 1, '2', 40, '114', 'A', '運休大樓游泳池前集合', '選', NULL, NULL, NULL, 0, '一', '7,8', '03', '(1)學習如何提升多元運動技能，充實自我，增加就學期間生活樂趣 (2)學習有關人體運動的知識，認識體育運動的內涵、本質、目的、功能和價值 (3)學習在從事體育活動和運動競賽中，如何發展更有效率的社會互動互助行為和待人處事之道 (4)學習新興體育運動休閒產業技術及知識，利用所學增加未來就業管道'),
(79, 'A778', '五人制棒球理論與實務', 'SC', '林朝揚', 'A', '', 40, NULL, 2, 1, '2', 40, '114', 'A', '上課地點:洪四川籃球場', '選', NULL, NULL, NULL, 0, '四', '3,4', '03', '1.認識運動正確操作過程，養成運動的良好習慣，並提升運動技能及充實體育相關的知識。 2.認識體適能相關的知識、培養運動的興趣，藉由體育課提升身體適應能力，並能運用於日常生活以達到學生身心與社交層面的健康狀態。 3.認識五人制棒球器材規則、基本傳接球、防守、打擊技巧等，全面提升五人制棒球各種相關的運動能力，及欣賞五人制棒球運動美感的能力。 4.了解五人制棒球的競賽規則，並能從實戰中確實遵守競賽規則及培養能擔任裁判的能力。 5.透過五人制棒球練習與比賽的機會去觀摩他人守備與擊球優點，提升初學者與純孰者技術能力。 6.建立同儕間相互學習觀摩的精神並建立公平、公正、勝不驕、敗不餒的運動家精神。 7.藉由學習參與五人制棒球獲得成就感；提升自我概念以利往後學習各種運動項目及事物。'),
(80, 'A785', '休閒概論', 'SC', '李福恩', 'A', 'K01-202', 40, NULL, 2, 1, '2', 40, '114', 'A', '運休系同學請勿選修', '選', NULL, NULL, NULL, 0, '一', '8,9', '03,04,05', '一、了解人與環境生態之關係，進而完全融入其中。 二、培養學生正確的觀念及建立良好的休閒活動習慣。 三、培養學生親和大地的觀念，學習優質生活的技能。 四、建立生命與環境生態永續並存與共容理念。'),
(81, 'A798', '資訊基本能力', 'SC', '董建弘', 'A', 'L01-108', 50, NULL, 2, 1, '2', 50, '114', 'A', '', '選', NULL, NULL, NULL, 0, '三', '10,11', '16', '使大學部學生具備基本資訊能力： 1.能對議題以資訊科技進行收集與彙整。 2.將自己的見解，有條理與脈絡地使用相關軟體做適當呈現。 3.資訊的收集與運用能遵守資訊倫理與智財權等相關規範。 期末以製作專題報告呈現學習成果。 本課程將以三個構面，來建立學生資訊基本素養，分別是運算思維、安全與社會議題以及軟體應用能力等。其中： 運算思維包含「計算機概論」、「程式設計」與「網際網路概論」，介紹近代資訊技術的演進與應用等新知。 安全與社會議題包含「資訊網路安全」與「資訊素養與倫理」，探討因資訊化所衍生的社會與法律相關問題以及可能的因應之道。 軟體應用能力採4D教學法，用示範、實作、同儕互相教導與反饋，建立「文書編輯」、「電子試算表」與「簡報軟體」等軟體操作與應用的基本能力，並將證照檢測融入教學中，於課程中輔以證照測驗的環境，採「即學即測即評」的方式，讓教學更科學化，也讓學子體驗與熟悉證照考試的施測方式。'),
(82, 'A799', '資訊安全概論', 'SC', '趙志宏', 'A', 'L01-107', 50, NULL, 2, 1, '2', 50, '114', 'A', '', '選', NULL, NULL, NULL, 0, '三', '5,6', '16', '<pre>(一) 課程內容的專業範疇說明： 隨著網際網路與科技的發展，我們愈來愈依賴資訊科技與網路所帶我們生活的便利性，然而，當我們愈來愈與資訊科技緊密結合在一起，網際網路運作的背後，卻是充滿著許多風險因子，並不是我們想像地如此安全，電影黑帽駭客，敘述著：『我們的世界緊密相連，我們的系統緊密相連，我們的身分不堪一擊，我們的國防不堪一擊，我們的家園不堪一擊，我們的秘密不堪一擊，我們的隱私不堪一擊，我們的財產也不堪一擊。』 電影雖然為了戲劇的張力有比較誇張的效果，但是，其中部分的情節卻是真的很有可能在現實中所發生的，如此，我們能不對資訊科技與網路的運用，保持著一個謹慎的態度嗎？因此，本課程將為學生介紹資訊安全的許多威脅，包括案例的介紹、電影賞析、短片欣賞等許多主題，採用比較生動活潑的方式，來讓大家重視資訊安全課題，再從不同的面向，來進一步地分析資訊安全系統的架構、駭客的攻擊手法、惡意的程式之後，也能了解可以採取怎樣的策略與制度，來防止人為的破壞與入侵，進一步加強我們在面對資訊科技與網路使用時的防禦力，對你對我都是有正面幫助的。 (二) 與校核心能力的關係： 本課程係本校通識教育正式課程規劃中，博雅通識的的一門課程，其所欲回應校訂「基本素養」指標為「科學素養」，所欲成就學子的能力為「創造力」，亦即培養學生具備資訊安全的素養，創造自己附加價值的能力。 (三) 與通識中心核心能力的關係： 對照於本校通識課程核心能力的養成設定，本課程希望能達成以下幾點具體目標，養成學子相關的能力： 1. 運用科技與資訊： (1) 學習資訊安全所遭遇的威脅、攻擊手法。 (2) 學習資訊安全的防禦、架構與設計。 2. 獨立思考與解決問題： (1) 能對資訊安全問題與不同角度的論點進行批判性的思考。 (2) 能在對資訊安全的議題進行分析理解之後，提出自己的看法。 (3) 瞭解對資訊安全架構與設計所可能遭遇的問題，進而整理出自己的看法並提出解決方案。 3. 多元文化與國際視野： (1) 能對國際間的資訊安全趨勢進行學習、理解，與重新詮釋。 (2) 能對國際間所設計的資訊安全管理架構有所理解與討論。 此外在「探索自我與發展潛能」、「積極態度與團隊合作」、等核心能力，在教學設計與學習成果的規劃中亦有相當的著墨。 </pre>'),
(83, '0102', '中文(下)', 'GR', '蔡郁焄', 'A', 'M01-206', 60, NULL, 2, 1, '2', 60, '114', 'A', '111學年度起學士班境外新生必須符合以下資格，始能選修此門課程。一、港澳生、陸生。二、具「TOCFL」B1成績或其他華語文檢測成績相當「TOCFL」B1以上之成績證明。三、具最近一年於境外修習720小時、境內360小時以上華語文課程之修課證明。四、通過本校華語檢定。', '必', NULL, NULL, NULL, 0, '一', '5,6', '04,16,10', '本課程以「寫作與表達」為核心能力導向，旨在透過系統化的寫作訓練，提升學生在不同場域的文字駕馭力與溝通素養。課程整體架構涵蓋「應用寫作」、「評論寫作」與「自由寫作」三大類別。為深化教學成效，本學期課程採「適性分流主題」教學模式，授課教師將依據其專業領域，從以下三大主題中擇二進行深度教學，引導學生在特定的寫作領域中的實踐： 一、應用寫作：職場溝通與實務解決本主題聚焦於「目的導向」與「受眾意識」的建立，旨在培養學生解決實務問題的能力。教學內容如Email、提案企劃、履歷自傳及專題報告等實用文書，訓練學生能依據不同的溝通對象與情境調整語氣，精準傳達資訊。透過實作演練，學生將學會如何以文字展現執行力，符合實務需求。 二、評論寫作：邏輯思辨與觀點論述本主題側重於「建立判準」與「證據論證」的訓練，旨在培養學生理性的批判思考能力。課程將引導學生針對文本、影視作品或社會議題，建立明確且客觀的評論標準，並運用具體證據來支撐立場，而非流於主觀的情緒宣洩。學生將在此過程中練習如何建構獨立觀點，並透過嚴謹的邏輯結構有效說服他人。 三、自由寫作：自我探索與風格創發本主題以「個人聲音」與「風格探索」為核心，旨在引導學生挖掘獨特的觀察視角與敘事潛能。透過隨筆、敘事散文、地方書寫或創意微小說等形式，鼓勵學生在書寫中細膩覺察自我情感與生命經驗。教學目標在於協助學生擺脫制式的寫作框架，探索屬於自己的敘事風格。 本門課聚焦於主題一和主題二，教學目標如下： 一、評論寫作：建構批判思辨與修辭分析能力對應課綱精神： 建立判準、證據論證、邏輯思辨。 本課具體目標： 。訓練學生運用修辭學三角（Ethos, Pathos, Logos）作為分析工具，針對當代文本、社群媒體資訊及公共議題建立客觀的評論標準。 。培養邏輯能力，能精準識別公共論述中的邏輯謬誤與情緒操弄，並運用嚴謹的證據來支撐個人觀點，達成理性論辯。 二、應用寫作：強化議題關懷與提案解決能力對應課綱精神： 目的導向、受眾意識、實務解決。 本課具體目標： 。引導學生走出教室，結合場域議題進行問題意識的發掘。 。訓練學生撰寫具備「受眾意識」的實務提案，學習如何針對特定對象（如政府單位、校方、社區大眾）調整論述策略，提出具備可行性的解決方案。 三、多模態敘事：整合多元媒介的溝通素養對應課綱精神： 寫作與表達、文字駕馭力。 本課具體目標： 。突破傳統純文字寫作框架，訓練學生整合文字、視覺與數位媒介。 。透過製作懶人包、影音腳本或口頭簡報等形式，提升在不同媒介場域中的資訊傳達力與說服美學。'),
(84, '0202', '中文(下)', 'GR', '蔡郁焄', 'A', 'M01-208', 51, NULL, 2, 1, '2', 60, '114', 'A', '111學年度起學士班境外新生必須符合以下資格，始能選修此門課程。一、港澳生、陸生。二、具「TOCFL」B1成績或其他華語文檢測成績相當「TOCFL」B1以上之成績證明。三、具最近一年於境外修習720小時、境內360小時以上華語文課程之修課證明。四、通過本校華語檢定。', '必', NULL, NULL, NULL, 0, '二', '1,2', '04,16,10', '本課程以「寫作與表達」為核心能力導向，旨在透過系統化的寫作訓練，提升學生在不同場域的文字駕馭力與溝通素養。課程整體架構涵蓋「應用寫作」、「評論寫作」與「自由寫作」三大類別。為深化教學成效，本學期課程採「適性分流主題」教學模式，授課教師將依據其專業領域，從以下三大主題中擇二進行深度教學，引導學生在特定的寫作領域中的實踐： 一、應用寫作：職場溝通與實務解決本主題聚焦於「目的導向」與「受眾意識」的建立，旨在培養學生解決實務問題的能力。教學內容如Email、提案企劃、履歷自傳及專題報告等實用文書，訓練學生能依據不同的溝通對象與情境調整語氣，精準傳達資訊。透過實作演練，學生將學會如何以文字展現執行力，符合實務需求。 二、評論寫作：邏輯思辨與觀點論述本主題側重於「建立判準」與「證據論證」的訓練，旨在培養學生理性的批判思考能力。課程將引導學生針對文本、影視作品或社會議題，建立明確且客觀的評論標準，並運用具體證據來支撐立場，而非流於主觀的情緒宣洩。學生將在此過程中練習如何建構獨立觀點，並透過嚴謹的邏輯結構有效說服他人。 三、自由寫作：自我探索與風格創發本主題以「個人聲音」與「風格探索」為核心，旨在引導學生挖掘獨特的觀察視角與敘事潛能。透過隨筆、敘事散文、地方書寫或創意微小說等形式，鼓勵學生在書寫中細膩覺察自我情感與生命經驗。教學目標在於協助學生擺脫制式的寫作框架，探索屬於自己的敘事風格。 本門課聚焦於主題一和主題二，教學目標如下： 一、評論寫作：建構批判思辨與修辭分析能力對應課綱精神： 建立判準、證據論證、邏輯思辨。 本課具體目標： 。訓練學生運用修辭學三角（Ethos, Pathos, Logos）作為分析工具，針對當代文本、社群媒體資訊及公共議題建立客觀的評論標準。 。培養邏輯能力，能精準識別公共論述中的邏輯謬誤與情緒操弄，並運用嚴謹的證據來支撐個人觀點，達成理性論辯。 二、應用寫作：強化議題關懷與提案解決能力對應課綱精神： 目的導向、受眾意識、實務解決。 本課具體目標： 。引導學生走出教室，結合場域議題進行問題意識的發掘。 。訓練學生撰寫具備「受眾意識」的實務提案，學習如何針對特定對象（如政府單位、校方、社區大眾）調整論述策略，提出具備可行性的解決方案。 三、多模態敘事：整合多元媒介的溝通素養對應課綱精神： 寫作與表達、文字駕馭力。 本課具體目標： 。突破傳統純文字寫作框架，訓練學生整合文字、視覺與數位媒介。 。透過製作懶人包、影音腳本或口頭簡報等形式，提升在不同媒介場域中的資訊傳達力與說服美學。'),
