(91, '3102', '中文(下)', 'GR', '陳猷青', 'A', 'B01-106', 60, NULL, 2, 1, '2', 60, '114', 'A', '111學年度起學士班境外新生必須符合以下資格，始能選修此門課程。一、港澳生、陸生。二、具「TOCFL」B1成績或其他華語文檢測成績相當「TOCFL」B1以上之成績證明。三、具最近一年於境外修習720小時、境內360小時以上華語文課程之修課證明。四、通過本校華語檢定。', '必', NULL, NULL, NULL, 0, '四', '1,2', '04,16,10', '本課程以「寫作與表達」為核心能力導向，旨在透過系統化的寫作訓練，提升學生在不同場域的文字駕馭力與溝通素養。課程整體架構涵蓋「應用寫作」、「評論寫作」與「自由寫作」三大類別。為深化教學成效，本學期課程採「適性分流主題」教學模式，授課教師將依據其專業領域，從以下三大主題中擇二進行深度教學，引導學生在特定的寫作領域中的實踐： 1.應用寫作：職場溝通與實務解決本主題聚焦於「目的導向」與「受眾意識」的建立，旨在培養學生解決實務問題的能力。教學內容如Email、提案企劃、履歷自傳及專題報告等實用文書，訓練學生能依據不同的溝通對象與情境調整語氣，精準傳達資訊。透過實作演練，學生將學會如何以文字展現執行力，符合實務需求。 2.評論寫作：邏輯思辨與觀點論述本主題側重於「建立判準」與「證據論證」的訓練，旨在培養學生理性的批判思考能力。課程將引導學生針對文本、影視作品或社會議題，建立明確且客觀的評論標準，並運用具體證據來支撐立場，而非流於主觀的情緒宣洩。學生將在此過程中練習如何建構獨立觀點，並透過嚴謹的邏輯結構有效說服他人。 3.自由寫作：自我探索與風格創發本主題以「個人聲音」與「風格探索」為核心，旨在引導學生挖掘獨特的觀察視角與敘事潛能。透過隨筆、敘事散文、地方書寫或創意微小說等形式，鼓勵學生在書寫中細膩覺察自我情感與生命經驗。教學目標在於協助學生擺脫制式的寫作框架，探索屬於自己的敘事風格。');
INSERT INTO `courses` (`id`, `course_code`, `course_name`, `department`, `professor`, `class_group`, `classroom`, `confirmed_students`, `cono`, `credits`, `grade`, `helf`, `max_students`, `open_year`, `pclass`, `remarks`, `required_elective`, `sclass`, `time_thu`, `updated_at`, `average_rating`, `class_day`, `class_period`, `sdgs`, `course_objectives`) VALUES
